afterLoad.c:script:
const svc = $scope.messageService;
if (!items || items.size() == 0) return;
const now = svc.getEventDaoEstimatedMaxTime();
const available = [];
for (let i = 0; i < items.size(); i++) {
    const evt = items.get(i);
    const isWaiting = evt.eventStatus == 0
        && (!evt.scheduleTime || evt.scheduleTime.getTime() <= now);
    const isExpiredClaimed = evt.eventStatus == 5
        && evt.leaseExpireTime && evt.leaseExpireTime.getTime() <= now;
    if (isWaiting || isExpiredClaimed) {
        available.push(evt);
    }
}
if (available.length == 0) {
    items.clear();
    return;
}
const claimed = svc.claimNonBroadcastEvents(available);
items.clear();
for (let j = 0; j < claimed.size(); j++) {
    items.add(claimed.get(j));
}
